Here's an example of how you could save a struct using the `imgui::SaveIniSettingsToDisk` function and the nlohmann json library:

```c++
#include <imgui.h>
#include <nlohmann/json.hpp>

// Define your struct here
struct MyStruct {
    int myInt;
    float myFloat;
    bool myBool;
    char myChar[16];
};

// Define a global instance of your struct
MyStruct myStruct = { 42, 3.14f, true, "Hello, world!" };

int main() {
    ImGui::CreateContext();

    // ...

    // Call imgui::SaveIniSettingsToDisk with a filename to save your settings
    ImGui::SaveIniSettingsToDisk("settings.ini");

    // Create an instance of a JSON object
    nlohmann::json j;

    // Add your struct's values to the JSON object
    j["myInt"] = myStruct.myInt;
    j["myFloat"] = myStruct.myFloat;
    j["myBool"] = myStruct.myBool;
    j["myChar"] = myStruct.myChar;

    // Use the dump() function to convert the JSON object to a string
    std::string jsonString = j.dump();

    // Save the JSON string to a file
    std::ofstream outFile("settings.json");
    outFile << jsonString;
    outFile.close();

    return 0;
}
```

This code saves your ImGui settings to a file called "settings.ini" using `imgui::SaveIniSettingsToDisk`. It then creates an instance of a JSON object and adds the values of your struct to it. Finally, it uses the `nlohmann::json::dump` function to convert the JSON object to a string and saves it to a file called "settings.json".

