    ImVec2 windowPos = ImGui::GetWindowPos();
    ImVec2 contentRegionMin = ImGui::GetWindowContentRegionMin();

    // Calculate the position of the button
    ImVec2 buttonPos(windowPos.x, windowPos.y + contentRegionMin.y + ImGui::GetFontSize() + ImGui::GetStyle().ItemSpacing.y);

    // Set the cursor position to the button location
    ImGui::SetCursorPos(buttonPos);

    // Display the button
    if (showButton) {
        if (ImGui::Button("My Button", ImVec2(100, 30))) {
            // ...
        }
    }

    // ...

    ImGui::End();
}
```

This code uses `ImGui::GetWindowPos()` to retrieve the position of the current window, `ImGui::GetWindowContentRegionMin()` to get the top-left point of the content region, `ImGui::GetFontSize()` to calculate the height of the text, and `ImGui::GetStyle().ItemSpacing.y` to add some extra space below the button.

The `ImGui::SetCursorPos()` function is then used to set the cursor position at the desired (bottom-left) position, and `ImGui::Button()` is called to display the button.

